    private static final MinecraftVersion CURRENT = VERSIONS.get(VersionDeserializer.from(System.getProperty("net.labymod.running-version")));

    static {
        for (MinecraftVersion version : VERSIONS.values()) {
            version.initialize(CURRENT);
        }
    }

    private static MinecraftVersion register(MinecraftVersion minecraftVersion) {
        VERSIONS.put(minecraftVersion.version(), minecraftVersion);
        return minecraftVersion;
    }

    public static MinecraftVersion current() {
        return CURRENT;
    }

    @NotNull
    public static MinecraftVersion byId(Version version) {
        MinecraftVersion selected = VERSIONS.get(version);
        if (selected == null) {
            throw new IllegalArgumentException(String.valueOf(version) + " could not be found.");
        }
        return selected;
    }
